# Scratch: как блок «если тогда»
pogoda = input("Какая сегодня погода? (солнце/дождь): ")
if pogoda == "солнце":
    print("Пойдём гулять!")
else:
    print("Давай программировать дома!")

# Scratch: как блок «если тогда иначе если тогда»
chas = int(input("Который час? (0-23): "))
if chas < 10:
    print("Доброе утро!")
elif chas < 17:
    print("Добрый день!")
else:
    print("Добрый вечер!")

# Scratch: как блок «повторить»
for raz in range(5):
    print(str(raz + 1) + " раз: Привет!")
